prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?modelId
  ?node
  ?nodeName
  ?message
  ?messageName
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?modelId .
  FILTER(?modelId = "1cd93309017949fdbebf0f7d7ea50b4a")

  ?choreo tai:belongsTo ?model .

  ?node tai:belongsTo ?choreo ;
        bbo:name ?nodeName .
  FILTER(CONTAINS(LCASE(STR(?nodeName)), LCASE("Car is returned")))

  # MessageFlow edges where node is source/target (note: uses string IDs)
  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo ;
      bboExt:sourceRef ?srcId ;
      bboExt:targetRef ?tgtId .

  FILTER(
    STRENDS(STR(?node), STR(?srcId)) ||
    STRENDS(STR(?node), STR(?tgtId))
  )

  OPTIONAL {
    ?mf bboExt:messageRef ?messageRef .
    BIND(STR(?messageRef) AS ?message)
  }

  OPTIONAL {
    ?msg a bboExt:Message ;
         tai:belongsTo ?choreo ;
         bbo:name ?messageName .
    ?msg bbo:id ?msgId .
    FILTER(STR(?msgId) = STR(?message))
  }
}
LIMIT 25

