prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?choreo
  ?mf
  ?srcId
  ?tgtId
  ?messageRef
  ?messageName
  ?messageId
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "1cd93309017949fdbebf0f7d7ea50b4a" .
  ?choreo tai:belongsTo ?model .

  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo ;
      bboExt:sourceRef ?srcId ;
      bboExt:targetRef ?tgtId .

  OPTIONAL {
    ?mf bboExt:messageRef ?messageRef .
  }

  OPTIONAL {
    ?msg a bboExt:Message ;
         tai:belongsTo ?choreo ;
         bbo:name ?messageName ;
         bbo:id ?messageId .
    FILTER(BOUND(?messageRef) && STR(?messageId) = STR(?messageRef))
  }

  FILTER(BOUND(?messageRef))
}
LIMIT 25

